 20	import { responseFlags } from 'utils/ResponseFlags';
 21	import { isParentKiosk, kioskContextMenuAction } from '../../components/Kiosk/KioskActions';
 22	import { Visualization, Node } from '@patternfly/react-topology';
 23	import { elems, selectAnd } from 'helpers/GraphHelpers';
 24	import { ExternalServiceInfo } from '../../types/StatusState';
 25	import { isMultiCluster } from '../../config';
 26	import { KialiIcon } from 'config/KialiIcon';
 27	import { GetTracingUrlProvider } from '../../utils/tracing/UrlProviders';
 28	
 29	type ReduxStateProps = {
 30	  externalServices: ExternalServiceInfo[];
 31	  kiosk: string;
 32	  provider?: string;
 33	};
 34	
 35	type ReduxDispatchProps = {
 36	  close: () => void;
 37	  setNode: (node?: NodeParamsType) => void;
 38	};
 39	
 40	type Props = ReduxStateProps &
 41	  ReduxDispatchProps & {
 42	    data: SummaryData;
 43	    graphType: GraphType;
 44	    onFocus?: (focusNode: FocusNode) => void;
 45	    trace: JaegerTrace;
 46	    tracingURL?: string;
 47	  };
 48	
 49	type State = {
 50	  selectedSpanID?: string;
 51	};
 52	
 53	const closeBoxStyle = kialiStyle({
 54	  float: 'right',
 55	  marginTop: '-0.5rem'
 56	});
 57	
 58	const nameStyle = kialiStyle({
 59	  display: 'inline-block',
 60	  maxWidth: '95%',
 61	  textOverflow: 'ellipsis',
 62	  overflow: 'hidden',
 63	  whiteSpace: 'nowrap'
 64	});
 65	
 66	const pStyle = kialiStyle({
 67	  paddingTop: '0.5rem',
 68	  $nest: {
 69	    '& button': {
 70	      fontSize: 'var(--graph-side-panel--font-size)',
 71	      paddingTop: '0.25rem',
 72	      paddingBottom: '0.25rem'
 73	    }
 74	  }
 75	});
 76	
 77	const spanSelectStyle = kialiStyle({
 78	  maxWidth: '100%'
 79	});
 80	
 81	const iconStyle = kialiStyle({
 82	  marginRight: '0.25rem'
 83	});
 84	
 85	class SummaryPanelTraceDetailsComponent extends React.Component<Props, State> {
 86	  constructor(props: Props) {
 87	    super(props);
 88	    this.state = { selectedSpanID: undefined };
 89	  }
 90	
 91	  componentDidUpdate(props: Props): void {
 92	    if (props.trace.traceID !== this.props.trace.traceID) {
 93	      this.setState({ selectedSpanID: undefined });
 94	    }
 95	  }
 96	
 97	  render(): React.ReactNode {
 98	    let node: any = {};
 99	    let nodeData: any = {};
100	
101	    if (this.props.data.summaryType === 'node') {
102	      node = this.props.data.summaryTarget;
103	      nodeData = node.getData();
104	    }
105	
106	    const tracesDetailsURL = nodeData.namespace
107	      ? `/namespaces/${nodeData.namespace}${
108	          nodeData.workload
109	            ? `/workloads/${nodeData.workload}`
110	            : nodeData.service
111	            ? `/services/${nodeData.service}`
112	            : `/applications/${nodeData.app!}`
113	        }?tab=traces&${URLParam.TRACING_TRACE_ID}=${this.props.trace.traceID}${
114	          nodeData.cluster && isMultiCluster ? `&${URLParam.CLUSTERNAME}=${encodeURIComponent(nodeData.cluster)}` : ''
115	        }`
116	      : undefined;
117	
118	    const tracingURLProvider = GetTracingUrlProvider(this.props.externalServices, this.props.provider);
119	
120	    const traceUrl = tracingURLProvider?.TraceUrl(this.props.trace);
121	
122	    const info = new FormattedTraceInfo(this.props.trace);
123	
124	    const title = (
125	      <span className={nameStyle}>
126	        {info.name()}
127	        <span className={shortIDStyle}>{info.shortID()}</span>
128	      </span>
129	    );
130	
131	    const spans: RichSpanData[] = nodeData['hasSpans'] ?? [];
132	    let currentSpan = spans.find(s => s.spanID === this.state.selectedSpanID);
133	
134	    if (!currentSpan && spans.length > 0) {
135	      currentSpan = spans[0];
136	    }
137	
138	    return (
139	      <>
140	        <div className={summaryTitle}>
141	          <span>Trace</span>
142	
143	          <span className={closeBoxStyle}>
144	            <Tooltip content="Close and clear trace selection">
145	              <Button id="close-trace" variant={ButtonVariant.plain} onClick={this.props.close}>
146	                <KialiIcon.Close />
147	              </Button>
148	            </Tooltip>
149	          </span>
150	        </div>
151	
152	        <div>
153	          {tracesDetailsURL ? (
154	            <Tooltip content={`View trace details for: ${info.name()}`}>
155	              <Link
156	                to={tracesDetailsURL}
157	                onClick={() => {
158	                  if (isParentKiosk(this.props.kiosk)) {
159	                    kioskContextMenuAction(tracesDetailsURL);
160	                  }
161	                }}
162	              >
163	                {title}
164	              </Link>
165	            </Tooltip>
166	          ) : (
167	            <Tooltip content={`${info.name()}`}>{title}</Tooltip>
168	          )}
169	          <div>
170	            {info.numErrors !== 0 && (
171	              <>
172	                <KialiIcon.ExclamationCircle color={PFColors.Danger} className={iconStyle} />
173	                <strong>This trace has {pluralize(info.numErrors, 'error')}.</strong>
174	              </>
175	            )}
176	            <div>
177	              <strong>Started: </strong>
178	              {info.fromNow()}
179	            </div>
180	
181	            {info.duration() && (
182	              <div>
183	                <strong>Full duration: </strong>
184	                {info.duration()}
185	              </div>
186	            )}
187	          </div>
188	
189	          {spans.length > 0 && (
190	            <div className={pStyle}>
191	              <div>
192	                <strong>{pluralize(spans.length, 'span')}</strong> on this node
193	                <SimpleSelect
194	                  selected={currentSpan?.operationName}
195	                  className={spanSelectStyle}
196	                  onSelect={key => {
197	                    this.setState({ selectedSpanID: key as string });
198	                  }}
199	                >
200	                  <SelectList>
201	                    {spans.map(s => {
202	                      return (
203	                        <SelectOption key={s.spanID} value={s.spanID}>
204	                          <>
205	                            <div>{s.operationName}</div>
206	                            <div>(t + {formatDuration(s.relativeStartTime)})</div>
207	                          </>
208	                        </SelectOption>
209	                      );
210	                    })}
211	                  </SelectList>
212	                </SimpleSelect>
213	              </div>
214	            </div>
215	          )}
216	
217	          {currentSpan && <div className={pStyle}>{this.renderSpan(currentSpan)}</div>}
218	
219	          {traceUrl && (
220	            <div style={{ marginTop: '0.25rem' }}>
221	              <a href={traceUrl} target="_blank" rel="noopener noreferrer">
222	                Show in Tracing
223	                <KialiIcon.ExternalLink className={iconStyle} />
224	              </a>
225	            </div>
226	          )}
227	        </div>
228	      </>
229	    );
230	  }
231	
232	  private spanViewLink(span: RichSpanData): string | undefined {
233	    const node = this.props.data.summaryTarget as Node;
234	    const nodeData = node.getData();
235	
236	    return nodeData.namespace
237	      ? `/namespaces/${nodeData.namespace}${
238	          nodeData.workload
239	            ? `/workloads/${nodeData.workload}`
240	            : nodeData.service
241	            ? `/services/${nodeData.service}`
242	            : `/applications/${nodeData.app!}`
243	        }?tab=traces&${URLParam.TRACING_TRACE_ID}=${this.props.trace.traceID}&${URLParam.TRACING_SPAN_ID}=${
244	          span.spanID
245	        }${span.cluster && isMultiCluster ? `&${URLParam.CLUSTERNAME}=${encodeURIComponent(span.cluster)}` : ''}`
246	      : undefined;
247	  }
248	
249	  private renderSpan(span: RichSpanData): React.ReactNode {
250	    const spanURL = this.spanViewLink(span);
251	
252	    return (
253	      <>
254	        <div>
255	          <strong>Started after: </strong>
256	          {formatDuration(span.relativeStartTime)}
257	        </div>
258	
259	        <div>
260	          <strong>Duration: </strong>
261	          {formatDuration(span.duration)}
262	        </div>
263	
264	        {(span.type === 'http' || span.type === 'envoy') && this.renderHTTPSpan(span)}
265	
266	        {span.type === 'tcp' && this.renderTCPSpan(span)}
267	
268	        <div>
269	          <strong>Related: </strong>
270	          {this.renderRelatedSpans(span)}
271	        </div>
272	
273	        {spanURL && (
274	          <div>
275	            <Link
276	              to={spanURL}
277	              onClick={() => {
278	                if (isParentKiosk(this.props.kiosk)) {
279	                  kioskContextMenuAction(spanURL);
280	                }
281	              }}
282	            >
283	              Show span
284	            </Link>
285	          </div>
286	        )}
287	      </>
288	    );
289	  }
290	
291	  private renderRelatedSpans(span: RichSpanData): React.ReactNode {
292	    type Related = { span: RichSpanData; text: string };
293	    const parent = findParent(span) as RichSpanData;
294	    const children = findChildren(span, this.props.trace) as RichSpanData[];
295	
296	    const related = ((parent ? [{ text: 'parent', span: parent }] : []) as Related[]).concat(
297	      children.map((child, idx) => ({ text: `child ${idx + 1}`, span: child }))
298	    );
299	
300	    return (
301	      <>
302	        {related.length > 0
303	          ? related.map(r => this.linkToSpan(span, r.span, r.text)).reduce((prev, curr) => [prev, ', ', curr] as any)
304	          : 'none'}
305	      </>
306	    );
307	  }
308	
309	  private linkToSpan(current: RichSpanData, target: RichSpanData, text: string): React.ReactNode {
310	    const useApp = this.props.graphType === GraphType.APP || this.props.graphType === GraphType.SERVICE;
311	    const currentElt = useApp ? current.app : current.workload;
312	    const targetElt = useApp ? target.app : target.workload;
313	
314	    let tooltipContent = <>{text}</>;
315	
316	    if (targetElt) {
317	      const controller =
318	        this.props.data.summaryType === 'graph'
319	          ? (this.props.data.summaryTarget as Visualization)
320	          : (this.props.data.summaryTarget as Node).getController();
321	
322	      if (!controller) {
323	        return <></>;
324	      }
325	
326	      const { nodes } = elems(controller);
327	
328	      const node = selectAnd(nodes, [
329	        { prop: NodeAttr.namespace, val: target.namespace },
330	        { prop: 'hasSpans', op: 'truthy' },
331	        { prop: useApp ? NodeAttr.app : NodeAttr.workload, val: targetElt }
332	      ]);
333	
334	      tooltipContent = (
335	        <>
336	          <Button
337	            variant={ButtonVariant.link}
338	            style={{ marginRight: '0.25rem' }}
339	            onClick={() => {
340	              this.setState({ selectedSpanID: target.spanID });
341	              if (targetElt !== currentElt || target.namespace !== current.namespace) {
342	                this.props.onFocus!({ id: node[0].getId(), isSelected: true });
343	              }
344	            }}
345	            isInline
346	          >
347	            <span style={summaryFont}>{text}</span>
348	          </Button>
349	
350	          <Button variant={ButtonVariant.link} onClick={() => this.props.onFocus!({ id: node[0].getId() })} isInline>
351	            <span style={summaryFont}>
352	              <KialiIcon.MapMarker />
353	            </span>
354	          </Button>
355	        </>
356	      );
357	    }
358	
359	    return (
360	      <Tooltip
361	        key={target.spanID}
362	        content={
363	          <>
364	            <div>Operation name: {target.operationName}</div>
365	            <div>Workload: {target.workload ?? 'unknown'}</div>
366	          </>
367	        }
368	      >
369	        {tooltipContent}
370	      </Tooltip>
371	    );
372	  }
373	
374	  private renderHTTPSpan(span: RichSpanData): React.ReactNode {
375	    const info = span.info as OpenTracingHTTPInfo | EnvoySpanInfo;
376	
377	    const rqLabel =
378	      info.direction === 'inbound' ? 'Inbound request' : info.direction === 'outbound' ? 'Outbound request' : 'Request';
379	
380	    const flag = (info as EnvoySpanInfo).responseFlags;
381	
382	    return (
383	      <>
384	        <div>
385	          <strong>{rqLabel}: </strong>
386	          {info.method} {info.url}
387	        </div>
388	
389	        <div>
390	          <strong>Response: </strong>
391	          code {info.statusCode ?? 'unknown'}
392	          {flag && `, flags ${flag}`}
393	        </div>
394	
395	        {flag && (
396	          <div>
397	            <KialiIcon.Info /> {responseFlags[flag]?.help ?? 'Unknown flag'}
398	          </div>
399	        )}
400	      </>
401	    );
402	  }
403	
404	  private renderTCPSpan(span: RichSpanData): React.ReactNode {
405	    const info = span.info as OpenTracingTCPInfo;
406	
407	    return (
408	      <>
409	        {info.topic && (
410	          <div>
411	            <strong>Topic: </strong>
412	            {info.topic}
413	          </div>
414	        )}
415	      </>
416	    );
417	  }
418	}
419	
420	const mapStateToProps = (state: KialiAppState): ReduxStateProps => ({
421	  externalServices: state.statusState.externalServices,
422	  kiosk: state.globalState.kiosk,
423	  provider: state.tracingState.info?.provider
424	});
425	
426	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => ({
427	  close: () => dispatch(TracingThunkActions.setTraceId('', undefined)),
428	  setNode: bindActionCreators(GraphActions.setNode, dispatch)
429	});
430	
431	export const SummaryPanelTraceDetails = connect(mapStateToProps, mapDispatchToProps)(SummaryPanelTraceDetailsComponent);

