291	  private renderRelatedSpans(span: RichSpanData): React.ReactNode {
292	    type Related = { span: RichSpanData; text: string };
293	    const parent = findParent(span) as RichSpanData;
294	    const children = findChildren(span, this.props.trace) as RichSpanData[];
295	
296	    const related = ((parent ? [{ text: 'parent', span: parent }] : []) as Related[]).concat(
297	      children.map((child, idx) => ({ text: `child ${idx + 1}`, span: child }))
298	    );
299	
300	    return (
301	      <>
302	        {related.length > 0
303	          ? related.map(r => this.linkToSpan(span, r.span, r.text)).reduce((prev, curr) => [prev, ', ', curr] as any)
304	          : 'none'}
305	      </>
306	    );
307	  }
