389	        <div>
390	          <strong>Response: </strong>
391	          code {info.statusCode ?? 'unknown'}
392	          {flag && `, flags ${flag}`}
393	        </div>
394	
395	        {flag && (
396	          <div>
397	            <KialiIcon.Info /> {responseFlags[flag]?.help ?? 'Unknown flag'}
398	          </div>
399	        )}
400	      </>
401	    );
402	  }
